#include <stddef.h>
#include <stdint.h>
#include "../../include/utf.h"
#include "../endianness.h"
size_t
utf8_length_from_utf16le (const utf16_t *data, size_t len) {
  size_t counter = 0;
  uint16_t word;
  for (size_t i = 0; i < len; i++) {
    word = utf_is_be() ? utf_swap_uint16(data[i]) : data[i];
    if (word <= 0x7f) {
      counter++;
    } else if (word <= 0x7ff) {
      counter += 2;
    } else if ((word <= 0xd7ff) || (word >= 0xe000)) {
      counter += 3;
    } else {
      counter += 2;
    }
  }
  return counter;
}
