bool
ascii_validate (const ascii_t *data, size_t len) {
  uint64_t pos = 0;
  for (; pos + 16 <= len; pos += 16) {
    uint64_t v1;
    memcpy(&v1, data + pos, sizeof(uint64_t));
    uint64_t v2;
    memcpy(&v2, data + pos + sizeof(uint64_t), sizeof(uint64_t));
    uint64_t v = v1 | v2;
    if ((v & 0x8080808080808080) != 0) {
      return false;
    }
  }
  for (; pos < len; pos++) {
    if (data[pos] >= 0b10000000) {
      return false;
    }
  }
  return true;
}
